const msg = $json.message || $json;
const chat = msg.chat || {};
const from = msg.from || {};
const text = (msg.text || '').trim();

if (!text) return [{ json: { action: 'skip' } }];

const chatId = String(chat.id);
const fromName = from.first_name || from.username || 'Unknown';
const isGroup = chat.type === 'group' || chat.type === 'supergroup';

// Only process group messages (meetings happen in groups)
// Also process DM commands for meeting management
const isDm = chat.type === 'private';

// Parse meeting commands
if (text.startsWith('/meeting')) {
  const parts = text.split(/\s+/);
  const subcommand = parts[1] || 'help';

  if (subcommand === 'start') {
    // /meeting start <topic> [agent1,agent2,...]
    const topic = parts.slice(2).join(' ') || 'Team Meeting';
    // Extract agents if specified with @
    const mentionedAgents = [];
    const agentMap = {
      'pm': 'product-manager',
      'planner': 'engineer-planner',
      'implementer': 'engineer-implementer',
      'reviewer': 'engineer-reviewer',
      'architect': 'architect',
      'security': 'security-agent',
      'qa': 'qa-agent',
      'ux': 'ux-agent',
      'ba': 'ba-agent',
      'marketing': 'marketing',
      'sales': 'sales-development',
      'tom': 'ask-dave-agent',
    };
    for (const part of parts) {
      if (part.startsWith('@')) {
        const name = part.slice(1).toLowerCase();
        if (agentMap[name]) mentionedAgents.push(agentMap[name]);
        else mentionedAgents.push(name);
      }
    }
    // Clean topic: remove @mentions
    const cleanTopic = parts.slice(2).filter(p => !p.startsWith('@')).join(' ') || 'Team Meeting';

    return [{ json: {
      action: 'start',
      topic: cleanTopic,
      agents: mentionedAgents.length > 0 ? mentionedAgents : ['product-manager', 'engineer-planner', 'architect'],
      chatId,
      fromName,
      messageId: String(msg.message_id)
    }}];
  }

  if (subcommand === 'end') {
    return [{ json: { action: 'end', chatId, fromName } }];
  }

  if (subcommand === 'status') {
    return [{ json: { action: 'status', chatId, fromName } }];
  }

  if (subcommand === 'invite') {
    const agentName = parts[2] || '';
    return [{ json: { action: 'invite', agent: agentName, chatId, fromName } }];
  }

  // Help
  return [{ json: { action: 'help', chatId, fromName } }];
}

// Regular message in a meeting group — route to active meeting
if (text.startsWith('/')) return [{ json: { action: 'skip' } }];

// Check if addressing a specific agent with @
let targetAgent = null;
const atMatch = text.match(/^@(\w+)/);
if (atMatch) {
  const agentMap = {
    'pm': 'product-manager',
    'planner': 'engineer-planner',
    'implementer': 'engineer-implementer',
    'reviewer': 'engineer-reviewer',
    'architect': 'architect',
    'security': 'security-agent',
    'qa': 'qa-agent',
    'ux': 'ux-agent',
    'ba': 'ba-agent',
    'marketing': 'marketing',
    'sales': 'sales-development',
    'tom': 'ask-dave-agent',
  };
  const name = atMatch[1].toLowerCase();
  targetAgent = agentMap[name] || name;
}

return [{ json: {
  action: 'message',
  text: text.replace(/^@\w+\s*/, ''),
  targetAgent,
  chatId,
  fromName,
  messageId: String(msg.message_id)
}}];

const result = $json;
const chatId = $node['Parse Meeting Command'].json.chatId;

let text;
if (result.ok) {
  const agents = result.agents.map(a => a.replace(/-/g, ' ')).join(', ');
  text = `*Meeting Started*\n\nTopic: ${result.topic}\nAgents: ${agents}\n\nSend messages in this group to discuss. Use @agent to address a specific agent.\n\nCommands:\n/meeting end - End meeting and get summary\n/meeting status - Check meeting state`;

  // Store meeting ID for this chat
  $execution.customData.set('meetingId_' + chatId, result.meetingId);
} else {
  text = 'Failed to start meeting: ' + (result.error || 'unknown error');
}

return [{ json: { chatId, text } }];

// Find active meeting for this chat
const chatId = $json.chatId;
const message = $json.text;
const fromName = $json.fromName;
const targetAgent = $json.targetAgent;

// Get meetings from runner
return [{ json: { chatId, message, fromName, targetAgent } }];

const meetingsData = $json;
const chatId = $node['Prepare Message'].json.chatId;
const message = $node['Prepare Message'].json.message;
const fromName = $node['Prepare Message'].json.fromName;
const targetAgent = $node['Prepare Message'].json.targetAgent;

// Find active meeting for this chat
const activeMeeting = (meetingsData.meetings || []).find(
  m => m.status === 'active' && m.telegram?.chatId === chatId
) || (meetingsData.meetings || []).find(
  m => m.status === 'active'
);

if (!activeMeeting) {
  return [{ json: { skip: true, chatId, text: 'No active meeting. Start one with /meeting start <topic>' } }];
}

const body = {
  message,
  from: fromName,
};

if (targetAgent) {
  body.agent = targetAgent;
}

return [{ json: {
  skip: false,
  meetingId: activeMeeting.meetingId,
  chatId,
  body
}}];

const chatId = $json.chatId;
const action = $json.action;

if (action === 'help') {
  return [{ json: { chatId, text: '*Meeting Commands*\n\n/meeting start <topic> @agent1 @agent2 - Start a meeting\n/meeting end - End meeting & get summary\n/meeting status - Check meeting state\n\n@pm / @planner / @architect / @reviewer / @security / @qa / @ux / @ba / @marketing / @sales / @tom / @implementer - Address a specific agent\n\nJust type normally to have all agents discuss.' }}];
}

if (action === 'status') {
  return [{ json: { chatId, text: '_Checking meeting status..._', checkStatus: true } }];
}

return [{ json: { chatId, text: 'Unknown command. Try /meeting help' } }];

const chatId = $node['Prepare End'].json.chatId;
const meetings = $json.meetings || [];
const active = meetings.find(m => m.status === 'active');

if (!active) {
  return [{ json: { skip: true, chatId, text: 'No active meeting to end.' } }];
}

return [{ json: { skip: false, meetingId: active.meetingId, chatId } }];

const result = $json;
const chatId = $node['Find Meeting to End'].json.chatId;

let text;
if (result.ok) {
  text = `*Meeting Ended*\n\n${result.summary || 'No summary generated.'}\n\n_${result.messageCount} messages total_`;
} else {
  text = 'Failed to end meeting: ' + (result.error || 'unknown');
}

// Truncate for Telegram
if (text.length > 4000) text = text.substring(0, 3990) + '...';

return [{ json: { chatId, text } }];
